// Lee from / to de la query del webhook. Si no llegan, defecto a
// los últimos 30 días. Devolvemos también la query de Zendesk Search
// que se le pasa al nodo "Get many tickets".
const q = $input.first().json.query || {};

function ymd(d) {
  return d.toISOString().slice(0, 10);
}
function parseYmd(s) {
  const m = String(s || '').match(/^\d{4}-\d{2}-\d{2}$/);
  return m ? s : null;
}

const now = new Date();
const defaultTo   = ymd(now);
const defaultFrom = ymd(new Date(now.getTime() - 29 * 86400000));

let from = parseYmd(q.from) || defaultFrom;
let to   = parseYmd(q.to)   || defaultTo;
if (from > to) { const t = from; from = to; to = t; }

// Zendesk Search: "created>=YYYY-MM-DD created<=YYYY-MM-DD type:ticket".
// Usamos < (estricto) sobre el día siguiente a `to` para incluir el
// día completo (Search es por fecha, no por timestamp).
function nextDay(s) {
  const d = new Date(s + 'T00:00:00Z');
  d.setUTCDate(d.getUTCDate() + 1);
  return ymd(d);
}
// Filtro Zendesk Search (versión IA — INVERSO del heatmap normal):
//  - type:ticket → solo tickets
//  - created>=X created<Y → rango (Y exclusivo, día completo de `to`)
//  - subject:"Conversation with" → SOLO tickets que SIGUEN en el agente
//    IA de Zendesk. Estos llegan con asunto "Conversation with <fulano>"
//    porque aún no se han derivado a un humano. El heatmap normal los
//    descarta; este informe los aísla para medir volumen de bot vs.
//    incidencias reales y la cobertura del agente IA.
const zdQuery = `type:ticket created>=${from} created<${nextDay(to)} subject:"Conversation with"`;

return [{ json: { from, to, zdQuery } }];

// Agrega los tickets por día de la semana (Lun=0..Dom=6) y hora
// (0..23) en una matriz 7x24. Devuelve también la lista bruta de
// tickets etiquetados con su bucket (day,hour) para que el front
// pueda hacer drill-down al pulsar una celda.
// Zona horaria: usamos Europe/Madrid (España) para que las horas
// coincidan con la jornada laboral del equipo.
const TZ = 'Europe/Madrid';

// ──────────────────────────────────────────────────────────
//  Custom fields de Zendesk a extraer
// ──────────────────────────────────────────────────────────
// Reemplaza los IDs por los reales de tu cuenta:
//   Zendesk → Admin Center → Objects and rules → Tickets → Fields
//   El ID es el numérico que aparece a la derecha del nombre del campo.
// Los campos cuyo ID quede en null se ignoran (front no los pinta).
// Si no conoces los IDs ahora, déjalos así y el resto de la respuesta
// sigue funcionando — el drawer mostrará id + asunto + estado.
const CUSTOM_FIELD_IDS = {
  tipo:    26672700540829,  // "Tipo de ticket"
  entorno: 27376906089629,  // "Entorno"
  modulo:  27243772817053   // "Módulo"
};

// Devuelve SIEMPRE un array de strings (vacío si no hay valor). Los
// custom fields multi-select de Zendesk llegan como cf.value array, los
// dropdown sencillos como string. Sin normalizar a array, el chip del
// drawer pintaría un literal de array al hacer toString.
function extraerCustomFieldArr(t, id) {
  if (id == null) return [];
  const fuentes = [t.custom_fields, t.fields].filter(Array.isArray);
  for (const arr of fuentes) {
    const cf = arr.find(c => c && (c.id === id || String(c.id) === String(id)));
    if (!cf) continue;
    const v = cf.value;
    if (v == null || v === '') return [];
    if (Array.isArray(v)) return v.map(x => String(x).trim()).filter(Boolean);
    return [String(v).trim()];
  }
  return [];
}
function extraerCustomField(t, id) {
  // Wrapper que devuelve string única para chips simples (primer valor,
  // o todos unidos con " · " si son varios). null si no hay nada.
  const arr = extraerCustomFieldArr(t, id);
  if (!arr.length) return null;
  return arr.length === 1 ? arr[0] : arr.join(' · ');
}

const items = $input.all();
const meta = $('Validar rango').first().json;

const matrix = Array.from({ length: 7 }, () => Array(24).fill(0));
const tickets = [];
let total = 0;

function bucket(date) {
  // Intl con timeZone para sacar día de semana y hora en horario de
  // España, sin tirar de librerías externas.
  const fmt = new Intl.DateTimeFormat('en-US', {
    timeZone: TZ,
    weekday: 'short',
    hour: 'numeric',
    hour12: false
  });
  const parts = fmt.formatToParts(date);
  const wd  = parts.find(p => p.type === 'weekday').value;   // Mon..Sun
  const hr  = parseInt(parts.find(p => p.type === 'hour').value, 10) % 24;
  const idx = ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd);
  return [idx, hr];
}

for (const it of items) {
  const t = it.json || {};
  // Backup del filtro Zendesk (INVERTIDO en este informe): mantenemos
  // SOLO los tickets que siguen en el agente IA — los que tienen
  // "Conversation with" en el asunto. Si por algún motivo se cuelan
  // tickets normales (Zendesk Search ignora el filtro), los descartamos.
  const subj = String(t.subject || '').trim().toLowerCase();
  if (!subj.startsWith('conversation with')) continue;
  const ts = t.created_at || t.createdAt || t.created;
  if (!ts) continue;
  const d = new Date(ts);
  if (isNaN(d.getTime())) continue;
  const [dia, hora] = bucket(d);
  if (dia < 0 || dia > 6 || hora < 0 || hora > 23) continue;
  matrix[dia][hora]++;
  total++;
  // Persistimos los campos que el front pinta en el drill-down.
  tickets.push({
    id: t.id != null ? t.id : (t.ticket_id || null),
    subject: t.subject || t.title || t.descripcion || '(sin título)',
    status: t.status || null,
    requester_id:    t.requester_id    || null,
    organization_id: t.organization_id || null,
    created_at: ts,
    day:  dia,
    hour: hora,
    // Custom fields configurables — se pintan como chips en el drawer.
    tipo:    extraerCustomField(t, CUSTOM_FIELD_IDS.tipo),
    entorno: extraerCustomField(t, CUSTOM_FIELD_IDS.entorno),
    modulo:  extraerCustomField(t, CUSTOM_FIELD_IDS.modulo)
  });
}

// Lista única de organization_id no nulos — el siguiente nodo HTTP
// los manda a Zendesk show_many para resolver los nombres en una sola
// llamada en vez de N (una por ticket).
const __org_ids = [...new Set(tickets.map(t => t.organization_id).filter(Boolean))];

return [{
  json: {
    from: meta.from,
    to:   meta.to,
    total,
    matrix,
    tickets,
    __org_ids
  }
}];

// Mergea los nombres de organización en cada ticket. Lee la respuesta
// de "Get organizations" (formato Zendesk: { organizations: [{id,name,...}] })
// y construye un Map id→name para hacer lookup en O(1) por ticket.
//
// Si Zendesk devolvió error o array vacío (porque la query iba con ids=0
// porque ningún ticket tenía org), todos los tickets quedan con
// organization_name: null sin romper nada.
const aggregated = $('Agregar matriz').first().json || {};
const orgsResp   = $input.first().json || {};
const orgsArr    = Array.isArray(orgsResp.organizations) ? orgsResp.organizations : [];
const orgMap     = new Map(orgsArr.map(o => [o.id, o.name]));

const tickets = (aggregated.tickets || []).map(t => ({
  ...t,
  organization_name: t.organization_id ? (orgMap.get(t.organization_id) || null) : null
}));

return [{ json: {
  from:   aggregated.from,
  to:     aggregated.to,
  total:  aggregated.total,
  matrix: aggregated.matrix,
  tickets
} }];
